void play(int &curr_max, int &curr_max_par, int &second_max, int &second_max_par, int first, int second, int idx){
    if(curr_max < first){
        curr_max = first;
        curr_max_par = idx&1;
    }
    if(second_max < second){
        second_max = second;
        second_max_par = idx&1;
    }
}

