int f4(vector<pair<int,int>> &c, int endidx, int curridx, int fmax, int fpar, int smax, int spar){
    if(curridx == endidx){
        return ((endidx&1) == (fpar)) + ((endidx&1) == (spar));
    }
    int tfmax = fmax, tfpar = fpar, tsmax = smax, tspar = spar;
    play(tfmax, tfpar, tsmax, tspar, c[curridx].st, c[curridx].nd, curridx);
    play(fmax, fpar, smax, spar, c[curridx].nd, c[curridx].st, curridx);
    
    int score1 = f4(c, endidx, (curridx + 1) % (c.size()), tfmax, tfpar, tsmax, tspar);
    int score2 = f4(c, endidx, (curridx + 1) % (c.size()), fmax, fpar, smax, spar);
    if((curridx&1) == (endidx&1)){
        return max(score1, score2);
    }
    return min(score1, score2);
}

int f3(vector<pair<int,int>> &c, int sidx){
    int score1 = f4(c, sidx, (sidx + 1) % (c.size()), c[sidx].st, sidx&1, c[sidx].nd, sidx&1);
    int score2 = f4(c, sidx, (sidx + 1) % (c.size()), c[sidx].nd, sidx&1, c[sidx].st, sidx&1);
    return max(score1, score2);
}

void f2(vector<pair<int,int>> &c){
    int n  = c.size();
    vector<int> outcome(n);
    for(int i = 0; i < n; i++){
        outcome[i] = f3(c, i);
        if(outcome[i] != 1 && (!(i&1))){
            outcome[i] ^= 2;
        }
    }
    outcomes[outcome].push_back(c);
}

void f1(int kzk, vector<int> &left){
    if(kzk == left.size() / 2){
        // if(check(cards)){
        //     print(cards);
        // }
        f2(cards);
        return;
    }
    for(int i = 0; i < left.size(); i++){
        if(left[i]){
            left[i] = 0;
            cards[kzk].st = i + 1;
            for(int j = i + 1; j < left.size(); j++){
                if(left[j]){
                    left[j] = 0;
                    cards[kzk].nd = j + 1;
                    f1(kzk + 1, left);
                    left[j] = 1;
                }
            }
            left[i] = 1;
        }
    }
}

